\$content = Get-Content app/page.tsx -Raw
\$content = \$content -replace '        const \{ error: uploadError \} = await supabase.storage\s*\.from\(''complaints''\)\s*\.upload\(filePath, evidenceFile\);(\s*)if \(uploadError\) throw new Error\([^)]*\);(\s*)const \{ data: \{ publicUrl \} \} = supabase.storage\s*\.from\(''complaints''\)\s*\.getPublicUrl\(filePath\);\s*evidenceUrl = publicUrl;', \"        const formData = new FormData();\r\n        formData.append(''file'', evidenceFile);\r\n        formData.append(''bucket'', ''complaints'');\r\n        const uploadRes = await fetch(''/api/upload'', \{\r\n          method: ''POST'',\r\n          body: formData,\r\n        \});\r\n        const uploadData = await uploadRes.json();\r\n        if (!uploadRes.ok) throw new Error(''鍥剧墖涓婁紶澶辫触: '' + uploadData.error);\r\n        evidenceUrl = uploadData.url;\"
Set-Content -Path app/page.tsx -Value \$content -Encoding UTF8
